// ═══════════════════════════════════════════
// INKJET — 200 Pattern Renderers
// ═══════════════════════════════════════════

import type { PatternConfig, PatternMeta, PatternCategory } from '../types'

type RenderFn = (c: Required<PatternConfig>, w: number, h: number) => string

// Seeded random
function seededRng(seed: number) {
  let s = seed
  return () => { s = (s * 16807 + 0) % 2147483647; return (s - 1) / 2147483646 }
}

function circle(cx: number, cy: number, r: number, fill: string, opacity = 1): string {
  return `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${fill}" opacity="${opacity}"/>`
}
function rect(x: number, y: number, w: number, h: number, fill: string, opacity = 1, rx = 0): string {
  return `<rect x="${x}" y="${y}" width="${w}" height="${h}" fill="${fill}" opacity="${opacity}"${rx ? ` rx="${rx}"` : ''}/>`
}
function line(x1: number, y1: number, x2: number, y2: number, stroke: string, sw: number, opacity = 1): string {
  return `<line x1="${x1}" y1="${y1}" x2="${x2}" y2="${y2}" stroke="${stroke}" stroke-width="${sw}" opacity="${opacity}"/>`
}
function path(d: string, fill: string, stroke: string, sw: number, opacity = 1): string {
  return `<path d="${d}" fill="${fill}" stroke="${stroke}" stroke-width="${sw}" opacity="${opacity}"/>`
}

const P: Record<string, RenderFn> = {}
const META: Record<string, PatternMeta> = {}

function reg(name: string, category: PatternCategory, desc: string, tags: string[], fn: RenderFn) {
  P[name] = fn
  META[name] = { name, category, description: desc, tags }
}

// ═══ DOTS (20) ═══
reg('dots', 'dots', 'Regular dot grid', ['dot', 'grid', 'basic'], (c, w, h) => circle(w/2, h/2, w*c.density*0.3, c.color, c.opacity))
reg('dots-offset', 'dots', 'Offset dot grid (brick pattern)', ['dot', 'offset'], (c, w, h) => circle(w/2, h/4, w*c.density*0.2, c.color, c.opacity) + circle(0, h*3/4, w*c.density*0.2, c.color, c.opacity) + circle(w, h*3/4, w*c.density*0.2, c.color, c.opacity))
reg('dots-random', 'dots', 'Scattered random dots', ['dot', 'random'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density * 8); i++) s += circle(rng()*w, rng()*h, 0.5+rng()*w*0.08, c.color, c.opacity*(0.3+rng()*0.7)); return s })
reg('halftone', 'dots', 'Halftone gradient dots', ['halftone', 'print'], (c, w, h) => { const r = w*0.35*c.density; return circle(w/2, h/2, r, c.color, c.opacity) })
reg('halftone-line', 'dots', 'Linear halftone', ['halftone', 'gradient'], (c, w, h) => { const r = w*0.3*c.density; return circle(w/2, h/2, r, c.color, c.opacity) })
reg('stipple', 'dots', 'Stipple texture', ['stipple', 'pointillism'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; const n = Math.ceil(c.density * 15); for (let i = 0; i < n; i++) s += circle(rng()*w, rng()*h, 0.3+rng()*0.8, c.color, c.opacity*(0.2+rng()*0.8)); return s })
reg('confetti', 'dots', 'Confetti sprinkle', ['confetti', 'playful'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density * 6); i++) { const x=rng()*w, y=rng()*h, a=rng()*360, sw=1+rng()*2; s += `<rect x="${x}" y="${y}" width="${sw}" height="${sw*2.5}" fill="${c.color}" opacity="${c.opacity}" transform="rotate(${a},${x},${y})"/>` } return s })
reg('bubbles', 'dots', 'Overlapping circles', ['bubble', 'organic'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 4; i++) s += `<circle cx="${rng()*w}" cy="${rng()*h}" r="${2+rng()*w*0.2*c.density}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity*0.5}"/>`; return s })
reg('polka', 'dots', 'Classic polka dots', ['polka', 'retro'], (c, w, h) => circle(w/2, h/2, w*0.25*c.density, c.color, c.opacity) + circle(0, 0, w*0.25*c.density, c.color, c.opacity) + circle(w, 0, w*0.25*c.density, c.color, c.opacity) + circle(0, h, w*0.25*c.density, c.color, c.opacity) + circle(w, h, w*0.25*c.density, c.color, c.opacity))
reg('rings', 'dots', 'Concentric rings', ['ring', 'circle'], (c, w, h) => `<circle cx="${w/2}" cy="${h/2}" r="${w*0.35*c.density}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>`)
reg('dots-diagonal', 'dots', 'Diagonal dot pattern', ['dot', 'diagonal'], (c, w, h) => circle(0, 0, w*0.15*c.density, c.color, c.opacity) + circle(w, h, w*0.15*c.density, c.color, c.opacity))
reg('dots-diamond', 'dots', 'Diamond arrangement dots', ['dot', 'diamond'], (c, w, h) => circle(w/2, 0, w*0.12*c.density, c.color, c.opacity) + circle(0, h/2, w*0.12*c.density, c.color, c.opacity) + circle(w, h/2, w*0.12*c.density, c.color, c.opacity) + circle(w/2, h, w*0.12*c.density, c.color, c.opacity))
reg('dots-gradient', 'dots', 'Size-varying dot field', ['dot', 'gradient'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 6; i++) { const x = rng()*w, y = rng()*h, r = 0.5+rng()*w*0.15*c.density; s += circle(x, y, r, c.color, c.opacity * (0.3+r/(w*0.15))); } return s })
reg('dots-hex', 'dots', 'Hexagonal dot packing', ['dot', 'hex'], (c, w, h) => circle(w*0.25, h*0.25, w*0.1*c.density, c.color, c.opacity) + circle(w*0.75, h*0.25, w*0.1*c.density, c.color, c.opacity) + circle(w*0.5, h*0.6, w*0.1*c.density, c.color, c.opacity))
reg('dots-cluster', 'dots', 'Clustered dot groups', ['dot', 'cluster'], (c, w, h) => { const cx = w/2, cy = h/2, r = w*0.08*c.density; return circle(cx, cy, r*1.5, c.color, c.opacity) + circle(cx+r*2, cy-r, r, c.color, c.opacity*0.7) + circle(cx-r*1.5, cy+r*1.5, r*0.8, c.color, c.opacity*0.5) })
reg('dots-trail', 'dots', 'Trailing dot sequence', ['dot', 'trail'], (c, w, h) => { let s = ''; for (let i = 0; i < 5; i++) { const t = i/4, r = w*0.04*(1+t*2)*c.density; s += circle(w*0.1+t*w*0.8, h*0.3+Math.sin(t*Math.PI)*h*0.4, r, c.color, c.opacity*(0.3+t*0.7)); } return s })
reg('dots-spiral', 'dots', 'Spiral dot arrangement', ['dot', 'spiral'], (c, w, h) => { let s = ''; for (let i = 0; i < 8; i++) { const a = i*0.8, r = 1+i*w*0.04, x = w/2+Math.cos(a)*r, y = h/2+Math.sin(a)*r; s += circle(x, y, w*0.05*c.density, c.color, c.opacity); } return s })
reg('dots-cross', 'dots', 'Cross-arranged dots', ['dot', 'cross'], (c, w, h) => circle(w/2, h/2, w*0.08*c.density, c.color, c.opacity) + circle(w/2, 0, w*0.06*c.density, c.color, c.opacity*0.5) + circle(w/2, h, w*0.06*c.density, c.color, c.opacity*0.5) + circle(0, h/2, w*0.06*c.density, c.color, c.opacity*0.5) + circle(w, h/2, w*0.06*c.density, c.color, c.opacity*0.5))
reg('dots-flower', 'dots', 'Flower-shaped dot cluster', ['dot', 'flower'], (c, w, h) => { let s = circle(w/2, h/2, w*0.08*c.density, c.color, c.opacity); for (let i = 0; i < 6; i++) { const a = i*Math.PI/3, d = w*0.2; s += circle(w/2+Math.cos(a)*d, h/2+Math.sin(a)*d, w*0.06*c.density, c.color, c.opacity*0.7); } return s })
reg('dots-wave', 'dots', 'Wave-positioned dots', ['dot', 'wave'], (c, w, h) => { let s = ''; for (let i = 0; i < 6; i++) { const x = i*w/5, y = h/2+Math.sin(i*1.2)*h*0.25; s += circle(x, y, w*0.06*c.density, c.color, c.opacity); } return s })

// ═══ LINES (20) ═══
reg('lines-horizontal', 'lines', 'Horizontal stripes', ['stripe', 'horizontal'], (c, w, h) => line(0, h/2, w, h/2, c.color, c.strokeWidth, c.opacity))
reg('lines-vertical', 'lines', 'Vertical stripes', ['stripe', 'vertical'], (c, w, h) => line(w/2, 0, w/2, h, c.color, c.strokeWidth, c.opacity))
reg('lines-diagonal', 'lines', 'Diagonal stripes', ['stripe', 'diagonal'], (c, w, h) => line(0, h, w, 0, c.color, c.strokeWidth, c.opacity))
reg('lines-diagonal-reverse', 'lines', 'Reverse diagonal stripes', ['stripe', 'diagonal'], (c, w, h) => line(0, 0, w, h, c.color, c.strokeWidth, c.opacity))
reg('crosshatch', 'lines', 'Crosshatch pattern', ['crosshatch', 'classic'], (c, w, h) => line(0, h, w, 0, c.color, c.strokeWidth, c.opacity) + line(0, 0, w, h, c.color, c.strokeWidth, c.opacity))
reg('crosshatch-fine', 'lines', 'Fine crosshatch', ['crosshatch', 'fine'], (c, w, h) => line(0, h, w, 0, c.color, c.strokeWidth*0.5, c.opacity*0.6) + line(0, 0, w, h, c.color, c.strokeWidth*0.5, c.opacity*0.6))
reg('pinstripe', 'lines', 'Thin pinstripes', ['pinstripe', 'tailoring'], (c, w, h) => line(w*0.3, 0, w*0.3, h, c.color, c.strokeWidth*0.5, c.opacity))
reg('railroad', 'lines', 'Railroad track lines', ['railroad', 'parallel'], (c, w, h) => line(w*0.3, 0, w*0.3, h, c.color, c.strokeWidth, c.opacity) + line(w*0.7, 0, w*0.7, h, c.color, c.strokeWidth, c.opacity))
reg('dashed-h', 'lines', 'Horizontal dashed lines', ['dash', 'horizontal'], (c, w, h) => `<line x1="0" y1="${h/2}" x2="${w}" y2="${h/2}" stroke="${c.color}" stroke-width="${c.strokeWidth}" stroke-dasharray="${w*0.3*c.density} ${w*0.2}" opacity="${c.opacity}"/>`)
reg('dashed-v', 'lines', 'Vertical dashed lines', ['dash', 'vertical'], (c, w, h) => `<line x1="${w/2}" y1="0" x2="${w/2}" y2="${h}" stroke="${c.color}" stroke-width="${c.strokeWidth}" stroke-dasharray="${h*0.3*c.density} ${h*0.2}" opacity="${c.opacity}"/>`)
reg('dotted-h', 'lines', 'Horizontal dotted lines', ['dotted', 'horizontal'], (c, w, h) => `<line x1="0" y1="${h/2}" x2="${w}" y2="${h/2}" stroke="${c.color}" stroke-width="${c.strokeWidth}" stroke-dasharray="${c.strokeWidth} ${w*0.15}" stroke-linecap="round" opacity="${c.opacity}"/>`)
reg('zigzag', 'lines', 'Zigzag line', ['zigzag', 'angular'], (c, w, h) => path(`M0,${h} L${w/2},0 L${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('herringbone', 'lines', 'Herringbone weave', ['herringbone', 'textile'], (c, w, h) => line(0, h, w/2, 0, c.color, c.strokeWidth, c.opacity) + line(w/2, 0, w, h, c.color, c.strokeWidth, c.opacity))
reg('chevron', 'lines', 'Chevron pattern', ['chevron', 'arrow'], (c, w, h) => path(`M0,${h*0.7} L${w/2},${h*0.3} L${w},${h*0.7}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('wavy-h', 'lines', 'Horizontal wavy line', ['wavy', 'organic'], (c, w, h) => path(`M0,${h/2} Q${w/4},${h*0.2} ${w/2},${h/2} Q${w*3/4},${h*0.8} ${w},${h/2}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('wavy-v', 'lines', 'Vertical wavy line', ['wavy', 'vertical'], (c, w, h) => path(`M${w/2},0 Q${w*0.2},${h/4} ${w/2},${h/2} Q${w*0.8},${h*3/4} ${w/2},${h}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('scallop', 'lines', 'Scalloped edge', ['scallop', 'decorative'], (c, w, h) => path(`M0,${h} Q${w/4},${h*0.3} ${w/2},${h} Q${w*3/4},${h*0.3} ${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('hatching', 'lines', 'Engraving-style hatching', ['hatch', 'engraving'], (c, w, h) => { let s = ''; const n = Math.ceil(c.density * 5); for (let i = 0; i < n; i++) s += line(0, i*h/n, w, i*h/n, c.color, c.strokeWidth*0.5, c.opacity*(0.3+i/n*0.7)); return s })
reg('scratch', 'lines', 'Scratch texture', ['scratch', 'rough'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*5); i++) s += line(rng()*w, rng()*h, rng()*w, rng()*h, c.color, c.strokeWidth*0.5, c.opacity*(0.2+rng()*0.5)); return s })
reg('contour', 'lines', 'Topographic contour', ['contour', 'map'], (c, w, h) => path(`M0,${h*0.6} Q${w*0.3},${h*0.2} ${w*0.5},${h*0.5} Q${w*0.7},${h*0.8} ${w},${h*0.4}`, 'none', c.color, c.strokeWidth, c.opacity))

// ═══ GRID (18) ═══
reg('grid', 'grid', 'Square grid', ['grid', 'square'], (c, w, h) => line(0, 0, w, 0, c.color, c.strokeWidth, c.opacity) + line(0, 0, 0, h, c.color, c.strokeWidth, c.opacity))
reg('grid-dot', 'grid', 'Grid intersection dots', ['grid', 'dot'], (c, w, h) => circle(0, 0, w*0.05*c.density+0.5, c.color, c.opacity))
reg('graph-paper', 'grid', 'Engineering graph paper', ['graph', 'engineering'], (c, w, h) => line(0, 0, w, 0, c.color, c.strokeWidth*0.5, c.opacity*0.4) + line(0, 0, 0, h, c.color, c.strokeWidth*0.5, c.opacity*0.4))
reg('blueprint', 'grid', 'Blueprint grid', ['blueprint', 'technical'], (c, w, h) => line(0, 0, w, 0, c.color, c.strokeWidth*0.5, c.opacity*0.3) + line(0, 0, 0, h, c.color, c.strokeWidth*0.5, c.opacity*0.3))
reg('isometric', 'grid', 'Isometric grid', ['isometric', '3d'], (c, w, h) => line(0, h, w/2, 0, c.color, c.strokeWidth*0.5, c.opacity*0.5) + line(w/2, 0, w, h, c.color, c.strokeWidth*0.5, c.opacity*0.5) + line(0, h/2, w, h/2, c.color, c.strokeWidth*0.5, c.opacity*0.3))
reg('hex-grid', 'grid', 'Hexagonal grid', ['hex', 'honeycomb'], (c, w, h) => path(`M${w*0.25},0 L0,${h*0.5} L${w*0.25},${h} L${w*0.75},${h} L${w},${h*0.5} L${w*0.75},0 Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('triangle-grid', 'grid', 'Triangular grid', ['triangle', 'grid'], (c, w, h) => line(0, h, w/2, 0, c.color, c.strokeWidth*0.5, c.opacity) + line(w/2, 0, w, h, c.color, c.strokeWidth*0.5, c.opacity) + line(0, h, w, h, c.color, c.strokeWidth*0.5, c.opacity))
reg('diamond-grid', 'grid', 'Diamond/rhombus grid', ['diamond', 'rhombus'], (c, w, h) => line(w/2, 0, w, h/2, c.color, c.strokeWidth, c.opacity) + line(w, h/2, w/2, h, c.color, c.strokeWidth, c.opacity) + line(w/2, h, 0, h/2, c.color, c.strokeWidth, c.opacity) + line(0, h/2, w/2, 0, c.color, c.strokeWidth, c.opacity))
reg('brick', 'grid', 'Brick wall pattern', ['brick', 'masonry'], (c, w, h) => line(0, h/2, w, h/2, c.color, c.strokeWidth, c.opacity) + line(0, 0, 0, h/2, c.color, c.strokeWidth, c.opacity) + line(w/2, h/2, w/2, h, c.color, c.strokeWidth, c.opacity))
reg('tile', 'grid', 'Ceramic tile pattern', ['tile', 'floor'], (c, w, h) => rect(0, 0, w, h, 'none', c.opacity, 0) + `<rect x="0" y="0" width="${w}" height="${h}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>`)
reg('basket-weave', 'grid', 'Basket weave grid', ['basket', 'weave'], (c, w, h) => line(0, h*0.25, w, h*0.25, c.color, c.strokeWidth, c.opacity*0.5) + line(0, h*0.75, w, h*0.75, c.color, c.strokeWidth, c.opacity*0.5) + line(w*0.25, 0, w*0.25, h, c.color, c.strokeWidth, c.opacity*0.5) + line(w*0.75, 0, w*0.75, h, c.color, c.strokeWidth, c.opacity*0.5))
reg('plaid', 'grid', 'Plaid/tartan pattern', ['plaid', 'tartan'], (c, w, h) => rect(0, h*0.3, w, h*0.15, c.color, c.opacity*0.15) + rect(w*0.3, 0, w*0.15, h, c.color, c.opacity*0.15) + line(0, h*0.5, w, h*0.5, c.color, c.strokeWidth, c.opacity*0.3))
reg('lattice', 'grid', 'Lattice overlay', ['lattice', 'trellis'], (c, w, h) => line(0, 0, w, h, c.color, c.strokeWidth, c.opacity*0.5) + line(w, 0, 0, h, c.color, c.strokeWidth, c.opacity*0.5))
reg('mesh', 'grid', 'Fine mesh screen', ['mesh', 'screen'], (c, w, h) => line(0, 0, w, 0, c.color, c.strokeWidth*0.3, c.opacity*0.3) + line(0, 0, 0, h, c.color, c.strokeWidth*0.3, c.opacity*0.3))
reg('parquet', 'grid', 'Parquet floor', ['parquet', 'floor'], (c, w, h) => line(0, 0, w, 0, c.color, c.strokeWidth, c.opacity) + line(0, 0, 0, h/2, c.color, c.strokeWidth, c.opacity) + line(w/2, h/2, w/2, h, c.color, c.strokeWidth, c.opacity) + line(0, h, w, h, c.color, c.strokeWidth, c.opacity))
reg('subway', 'grid', 'Subway tile pattern', ['subway', 'metro'], (c, w, h) => `<rect x="1" y="1" width="${w-2}" height="${h/2-2}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}" rx="1"/>`)
reg('shingle', 'grid', 'Roof shingle pattern', ['shingle', 'roof'], (c, w, h) => path(`M0,${h} Q${w/2},${h*0.4} ${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('cobblestone', 'grid', 'Irregular cobblestone', ['cobble', 'stone'], (c, w, h) => { const rng = seededRng(c.seed); return `<rect x="${1+rng()*2}" y="${1+rng()*2}" width="${w-4-rng()*3}" height="${h-4-rng()*3}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}" rx="${1+rng()*3}"/>` })

// ═══ GEOMETRIC (20) ═══
reg('triangles', 'geometric', 'Equilateral triangles', ['triangle'], (c, w, h) => path(`M${w/2},${h*0.15} L${w*0.85},${h*0.85} L${w*0.15},${h*0.85} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('hexagons', 'geometric', 'Hexagons', ['hexagon', 'honeycomb'], (c, w, h) => path(`M${w*0.5},${h*0.05} L${w*0.93},${h*0.25} L${w*0.93},${h*0.75} L${w*0.5},${h*0.95} L${w*0.07},${h*0.75} L${w*0.07},${h*0.25} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('diamonds', 'geometric', 'Diamond shapes', ['diamond', 'rhombus'], (c, w, h) => path(`M${w/2},${h*0.1} L${w*0.9},${h/2} L${w/2},${h*0.9} L${w*0.1},${h/2} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('octagons', 'geometric', 'Octagon tiles', ['octagon'], (c, w, h) => { const d = w*0.2; return path(`M${d},0 L${w-d},0 L${w},${d} L${w},${h-d} L${w-d},${h} L${d},${h} L0,${h-d} L0,${d} Z`, 'none', c.color, c.strokeWidth, c.opacity) })
reg('stars-5', 'geometric', 'Five-point stars', ['star', 'five'], (c, w, h) => { let d = 'M'; for (let i = 0; i < 10; i++) { const a = i*Math.PI/5-Math.PI/2, r = (i%2===0?w*0.4:w*0.18)*c.density; d += `${w/2+Math.cos(a)*r},${h/2+Math.sin(a)*r} ` } return path(d+'Z', c.color, 'none', 0, c.opacity) })
reg('stars-6', 'geometric', 'Six-point stars', ['star', 'six', 'david'], (c, w, h) => { const r = w*0.35*c.density; return path(`M${w/2},${h/2-r} L${w/2+r*0.87},${h/2+r*0.5} L${w/2-r*0.87},${h/2+r*0.5} Z`, 'none', c.color, c.strokeWidth, c.opacity) + path(`M${w/2},${h/2+r} L${w/2+r*0.87},${h/2-r*0.5} L${w/2-r*0.87},${h/2-r*0.5} Z`, 'none', c.color, c.strokeWidth, c.opacity) })
reg('crosses', 'geometric', 'Plus/cross shapes', ['cross', 'plus'], (c, w, h) => { const t = w*0.15; return rect(w/2-t, h*0.15, t*2, h*0.7, c.color, c.opacity) + rect(w*0.15, h/2-t, w*0.7, t*2, c.color, c.opacity) })
reg('arrows-up', 'geometric', 'Upward arrows', ['arrow', 'direction'], (c, w, h) => path(`M${w/2},${h*0.15} L${w*0.8},${h*0.55} L${w*0.6},${h*0.55} L${w*0.6},${h*0.85} L${w*0.4},${h*0.85} L${w*0.4},${h*0.55} L${w*0.2},${h*0.55} Z`, c.color, 'none', 0, c.opacity))
reg('circles-nested', 'geometric', 'Concentric circles', ['circle', 'nested'], (c, w, h) => { let s = ''; const n = Math.ceil(3*c.density); for (let i = n; i > 0; i--) s += `<circle cx="${w/2}" cy="${h/2}" r="${w*0.4*i/n}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity*(i/n)}"/>`; return s })
reg('squares-nested', 'geometric', 'Nested squares', ['square', 'nested'], (c, w, h) => { let s = ''; const n = Math.ceil(3*c.density); for (let i = 0; i < n; i++) { const p = w*0.1*(i+1); s += `<rect x="${p}" y="${p}" width="${w-p*2}" height="${h-p*2}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity*(1-i/n)}"/>` } return s })
reg('penrose', 'geometric', 'Penrose-like tiling', ['penrose', 'aperiodic'], (c, w, h) => path(`M${w*0.5},${h*0.1} L${w*0.9},${h*0.4} L${w*0.7},${h*0.9} L${w*0.3},${h*0.9} L${w*0.1},${h*0.4} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('sierpinski', 'geometric', 'Sierpinski triangle', ['sierpinski', 'fractal'], (c, w, h) => path(`M${w/2},${h*0.1} L${w*0.9},${h*0.9} L${w*0.1},${h*0.9} Z M${w*0.3},${h*0.5} L${w*0.7},${h*0.5} L${w*0.5},${h*0.9} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('mosaic', 'geometric', 'Mosaic tile', ['mosaic', 'tile'], (c, w, h) => rect(0, 0, w*0.45, h*0.45, c.color, c.opacity*0.3) + rect(w*0.55, h*0.55, w*0.45, h*0.45, c.color, c.opacity*0.3))
reg('pinwheel', 'geometric', 'Pinwheel rotation', ['pinwheel', 'spin'], (c, w, h) => path(`M${w/2},${h/2} L${w},0 L${w},${h/2} Z`, c.color, 'none', 0, c.opacity*0.4) + path(`M${w/2},${h/2} L0,${h} L0,${h/2} Z`, c.color, 'none', 0, c.opacity*0.4))
reg('tessellation', 'geometric', 'Interlocking shapes', ['tessellation', 'escher'], (c, w, h) => path(`M0,${h*0.3} L${w*0.3},0 L${w},${h*0.3} L${w*0.7},${h} L0,${h*0.7} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('kite', 'geometric', 'Kite shapes', ['kite', 'rhombus'], (c, w, h) => path(`M${w/2},0 L${w*0.8},${h*0.35} L${w/2},${h} L${w*0.2},${h*0.35} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('spiral-square', 'geometric', 'Square spiral', ['spiral', 'square'], (c, w, h) => path(`M${w*0.1},${h*0.1} L${w*0.9},${h*0.1} L${w*0.9},${h*0.9} L${w*0.1},${h*0.9} L${w*0.1},${h*0.3} L${w*0.7},${h*0.3} L${w*0.7},${h*0.7} L${w*0.3},${h*0.7} L${w*0.3},${h*0.5}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('cube', 'geometric', 'Isometric cube', ['cube', '3d'], (c, w, h) => path(`M${w/2},${h*0.15} L${w*0.85},${h*0.35} L${w*0.85},${h*0.7} L${w/2},${h*0.9} L${w*0.15},${h*0.7} L${w*0.15},${h*0.35} Z M${w/2},${h*0.5} L${w*0.85},${h*0.35} M${w/2},${h*0.5} L${w*0.15},${h*0.35} M${w/2},${h*0.5} L${w/2},${h*0.9}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('flower-of-life', 'geometric', 'Sacred geometry flower', ['flower', 'sacred'], (c, w, h) => { let s = ''; for (let i = 0; i < 6; i++) { const a = i*Math.PI/3, r = w*0.25; s += `<circle cx="${w/2+Math.cos(a)*r*0.5}" cy="${h/2+Math.sin(a)*r*0.5}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.5}"/>` } return `<circle cx="${w/2}" cy="${h/2}" r="${w*0.25}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>` + s })
reg('meander', 'geometric', 'Greek key pattern', ['meander', 'greek'], (c, w, h) => path(`M0,${h} L0,${h*0.3} L${w*0.7},${h*0.3} L${w*0.7},${h*0.7} L${w*0.3},${h*0.7} L${w*0.3},${h}`, 'none', c.color, c.strokeWidth, c.opacity))

// ═══ ORGANIC (18) ═══
reg('leaves', 'organic', 'Leaf shapes', ['leaf', 'nature'], (c, w, h) => path(`M${w*0.2},${h*0.8} Q${w*0.2},${h*0.2} ${w*0.5},${h*0.15} Q${w*0.8},${h*0.2} ${w*0.8},${h*0.8} Q${w*0.5},${h*0.6} ${w*0.2},${h*0.8}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('branches', 'organic', 'Tree branch network', ['branch', 'tree'], (c, w, h) => path(`M${w*0.1},${h} L${w*0.5},${h*0.4} L${w*0.9},${h*0.1} M${w*0.5},${h*0.4} L${w*0.2},${h*0.1}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('vines', 'organic', 'Curving vine tendrils', ['vine', 'plant'], (c, w, h) => path(`M0,${h} Q${w*0.3},${h*0.3} ${w*0.5},${h*0.5} Q${w*0.7},${h*0.7} ${w},0`, 'none', c.color, c.strokeWidth, c.opacity))
reg('pebbles', 'organic', 'Smooth pebble shapes', ['pebble', 'stone'], (c, w, h) => { const rng = seededRng(c.seed); return `<ellipse cx="${w*0.3+rng()*w*0.2}" cy="${h*0.3+rng()*h*0.2}" rx="${w*0.15+rng()*w*0.1}" ry="${h*0.12+rng()*h*0.08}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>` })
reg('cells', 'organic', 'Biological cell shapes', ['cell', 'biology'], (c, w, h) => `<circle cx="${w/2}" cy="${h/2}" r="${w*0.35}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>` + circle(w*0.4, h*0.4, w*0.08, c.color, c.opacity*0.5))
reg('scales', 'organic', 'Fish scale pattern', ['scale', 'fish'], (c, w, h) => path(`M0,${h} Q${w/2},${h*0.1} ${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('feathers', 'organic', 'Feather barb pattern', ['feather', 'bird'], (c, w, h) => line(w/2, 0, w/2, h, c.color, c.strokeWidth, c.opacity) + path(`M${w/2},${h*0.3} Q${w*0.8},${h*0.2} ${w*0.9},${h*0.5}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.5) + path(`M${w/2},${h*0.3} Q${w*0.2},${h*0.2} ${w*0.1},${h*0.5}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.5))
reg('coral', 'organic', 'Coral branch structure', ['coral', 'reef'], (c, w, h) => { const rng = seededRng(c.seed); let d = `M${w/2},${h}`; for (let i = 0; i < 4; i++) d += ` Q${rng()*w},${h-rng()*h} ${w*0.3+rng()*w*0.4},${h*0.2+rng()*h*0.3}`; return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('wood-grain', 'organic', 'Wood grain texture', ['wood', 'grain'], (c, w, h) => { let s = ''; for (let i = 0; i < 4; i++) { const y = h*0.15+i*h*0.2; s += path(`M0,${y} Q${w*0.3},${y-3} ${w*0.5},${y+2} Q${w*0.7},${y+5} ${w},${y-1}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*(0.2+i*0.15)); } return s })
reg('marble', 'organic', 'Marble vein pattern', ['marble', 'stone'], (c, w, h) => { const rng = seededRng(c.seed); return path(`M${rng()*w*0.2},0 Q${w*0.3+rng()*w*0.3},${h*0.3+rng()*h*0.2} ${w*0.6+rng()*w*0.2},${h*0.5+rng()*h*0.2} Q${w*0.8},${h*0.8} ${w},${h}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.4) })
reg('moss', 'organic', 'Organic moss clusters', ['moss', 'nature'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*8); i++) s += circle(rng()*w, rng()*h, 0.5+rng()*2, c.color, c.opacity*(0.1+rng()*0.4)); return s })
reg('mushroom', 'organic', 'Mushroom cap shapes', ['mushroom', 'fungus'], (c, w, h) => path(`M${w*0.3},${h*0.6} Q${w*0.3},${h*0.2} ${w*0.5},${h*0.2} Q${w*0.7},${h*0.2} ${w*0.7},${h*0.6}`, 'none', c.color, c.strokeWidth, c.opacity) + line(w/2, h*0.6, w/2, h*0.9, c.color, c.strokeWidth, c.opacity))
reg('roots', 'organic', 'Root system branching', ['root', 'underground'], (c, w, h) => path(`M${w/2},0 L${w/2},${h*0.4} L${w*0.2},${h*0.8} M${w/2},${h*0.4} L${w*0.8},${h*0.9} M${w/2},${h*0.3} L${w*0.35},${h*0.6}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('clouds', 'organic', 'Cloud shapes', ['cloud', 'sky'], (c, w, h) => path(`M${w*0.2},${h*0.6} Q${w*0.15},${h*0.3} ${w*0.35},${h*0.3} Q${w*0.4},${h*0.1} ${w*0.55},${h*0.25} Q${w*0.75},${h*0.15} ${w*0.75},${h*0.35} Q${w*0.9},${h*0.35} ${w*0.85},${h*0.55} Q${w*0.85},${h*0.65} ${w*0.7},${h*0.6} Z`, 'none', c.color, c.strokeWidth, c.opacity))
reg('rain', 'organic', 'Rain drops', ['rain', 'weather'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*6); i++) s += line(rng()*w, rng()*h, rng()*w+1, rng()*h+h*0.2, c.color, c.strokeWidth*0.5, c.opacity*(0.2+rng()*0.5)); return s })
reg('snowflake', 'organic', 'Snowflake crystal', ['snowflake', 'winter'], (c, w, h) => { let s = ''; for (let i = 0; i < 6; i++) { const a = i*Math.PI/3, r = w*0.35; s += line(w/2, h/2, w/2+Math.cos(a)*r, h/2+Math.sin(a)*r, c.color, c.strokeWidth, c.opacity); s += line(w/2+Math.cos(a)*r*0.5, h/2+Math.sin(a)*r*0.5, w/2+Math.cos(a+0.4)*r*0.3, h/2+Math.sin(a+0.4)*r*0.3, c.color, c.strokeWidth*0.5, c.opacity*0.6) } return s })
reg('wave-organic', 'organic', 'Organic flowing wave', ['wave', 'flow'], (c, w, h) => path(`M0,${h*0.5} C${w*0.25},${h*0.2} ${w*0.4},${h*0.8} ${w*0.6},${h*0.4} C${w*0.8},${h*0.1} ${w*0.9},${h*0.7} ${w},${h*0.5}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('terrain', 'organic', 'Terrain elevation lines', ['terrain', 'topography'], (c, w, h) => { let s = ''; for (let i = 0; i < 3; i++) { const y = h*0.2+i*h*0.25; s += path(`M0,${y+i*5} Q${w*0.25},${y-8+i*3} ${w*0.5},${y+4} Q${w*0.75},${y+12-i*4} ${w},${y-2+i*6}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*(0.3+i*0.2)) } return s })

// ═══ TEXTURE (16) ═══
reg('noise-fine', 'texture', 'Fine noise grain', ['noise', 'grain'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*20); i++) s += rect(rng()*w, rng()*h, 0.5+rng(), 0.5+rng(), c.color, c.opacity*(0.05+rng()*0.2)); return s })
reg('noise-coarse', 'texture', 'Coarse noise', ['noise', 'rough'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*10); i++) s += rect(rng()*w, rng()*h, 1+rng()*3, 1+rng()*3, c.color, c.opacity*(0.05+rng()*0.15)); return s })
reg('canvas', 'texture', 'Canvas fabric texture', ['canvas', 'fabric'], (c, w, h) => line(0, h*0.33, w, h*0.33, c.color, c.strokeWidth*0.3, c.opacity*0.15) + line(0, h*0.66, w, h*0.66, c.color, c.strokeWidth*0.3, c.opacity*0.15) + line(w*0.33, 0, w*0.33, h, c.color, c.strokeWidth*0.3, c.opacity*0.15) + line(w*0.66, 0, w*0.66, h, c.color, c.strokeWidth*0.3, c.opacity*0.15))
reg('linen', 'texture', 'Linen weave texture', ['linen', 'fabric'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 4; i++) s += line(0, i*h/3+rng()*2, w, i*h/3-rng()*2, c.color, c.strokeWidth*0.3, c.opacity*(0.08+rng()*0.1)); for (let i = 0; i < 4; i++) s += line(i*w/3+rng()*2, 0, i*w/3-rng()*2, h, c.color, c.strokeWidth*0.3, c.opacity*(0.08+rng()*0.1)); return s })
reg('paper', 'texture', 'Paper fiber texture', ['paper', 'fiber'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*12); i++) { const x=rng()*w, y=rng()*h, l=rng()*3; s += line(x, y, x+l, y+rng()*2-1, c.color, 0.3, c.opacity*(0.03+rng()*0.08)) } return s })
reg('concrete', 'texture', 'Concrete surface', ['concrete', 'industrial'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*15); i++) s += rect(rng()*w, rng()*h, rng()*2, rng()*2, c.color, c.opacity*(0.02+rng()*0.06)); return s })
reg('sandstone', 'texture', 'Sandstone granular', ['sand', 'stone'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*25); i++) s += circle(rng()*w, rng()*h, 0.3+rng()*0.6, c.color, c.opacity*(0.03+rng()*0.08)); return s })
reg('denim', 'texture', 'Denim twill weave', ['denim', 'fabric'], (c, w, h) => line(0, h, w, 0, c.color, c.strokeWidth*0.3, c.opacity*0.12) + line(0, h*0.5, w*0.5, 0, c.color, c.strokeWidth*0.3, c.opacity*0.08) + line(w*0.5, h, w, h*0.5, c.color, c.strokeWidth*0.3, c.opacity*0.08))
reg('leather', 'texture', 'Leather grain', ['leather', 'hide'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 6; i++) { const x=rng()*w, y=rng()*h; s += path(`M${x},${y} Q${x+rng()*4-2},${y+rng()*4-2} ${x+rng()*3},${y+rng()*3}`, 'none', c.color, 0.3, c.opacity*0.08) } return s })
reg('silk', 'texture', 'Silk sheen lines', ['silk', 'fabric'], (c, w, h) => { let s = ''; for (let i = 0; i < 3; i++) s += line(0, i*h/2.5, w, i*h/2.5+h*0.1, c.color, c.strokeWidth*0.2, c.opacity*0.06); return s })
reg('rust', 'texture', 'Rust spots', ['rust', 'decay'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*8); i++) { const r = 0.5+rng()*w*0.08; s += circle(rng()*w, rng()*h, r, c.color, c.opacity*(0.05+rng()*0.15)) } return s })
reg('brushed-metal', 'texture', 'Brushed metal finish', ['metal', 'brushed'], (c, w, h) => { let s = ''; for (let i = 0; i < 8; i++) s += line(0, i*h/7, w, i*h/7+0.5, c.color, 0.3, c.opacity*(0.03+i*0.01)); return s })
reg('carbon-fiber', 'texture', 'Carbon fiber weave', ['carbon', 'fiber'], (c, w, h) => line(0, h, w, 0, c.color, c.strokeWidth*0.5, c.opacity*0.15) + line(0, 0, w, h, c.color, c.strokeWidth*0.5, c.opacity*0.15) + rect(0, 0, w/2, h/2, c.color, c.opacity*0.03) + rect(w/2, h/2, w/2, h/2, c.color, c.opacity*0.03))
reg('film-grain', 'texture', 'Film grain overlay', ['film', 'grain'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*30); i++) s += rect(rng()*w, rng()*h, rng()>.5?1:0.5, rng()>.5?1:0.5, c.color, c.opacity*(0.02+rng()*0.06)); return s })
reg('stucco', 'texture', 'Stucco wall texture', ['stucco', 'plaster'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*10); i++) { const cx=rng()*w, cy=rng()*h, rx=1+rng()*2, ry=0.5+rng()*1.5; s += `<ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${c.color}" opacity="${c.opacity*(0.03+rng()*0.06)}"/>` } return s })
reg('terrazzo', 'texture', 'Terrazzo chips', ['terrazzo', 'floor'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*5); i++) { const x=rng()*w, y=rng()*h, sz=2+rng()*4; const d = `M${x},${y} L${x+sz},${y+rng()*sz*0.5} L${x+sz*0.7},${y+sz} L${x-sz*0.3},${y+sz*0.7} Z`; s += path(d, c.color, 'none', 0, c.opacity*(0.1+rng()*0.2)) } return s })

// ═══ TECHNICAL (18) ═══
reg('circuit', 'technical', 'Circuit board traces', ['circuit', 'pcb'], (c, w, h) => line(0, h/2, w*0.4, h/2, c.color, c.strokeWidth, c.opacity) + line(w*0.4, h/2, w*0.4, h*0.2, c.color, c.strokeWidth, c.opacity) + line(w*0.4, h*0.2, w, h*0.2, c.color, c.strokeWidth, c.opacity) + circle(w*0.4, h/2, 2, c.color, c.opacity))
reg('circuit-dot', 'technical', 'Circuit with nodes', ['circuit', 'node'], (c, w, h) => line(w*0.2, h*0.2, w*0.8, h*0.8, c.color, c.strokeWidth*0.5, c.opacity) + circle(w*0.2, h*0.2, 2, c.color, c.opacity) + circle(w*0.8, h*0.8, 2, c.color, c.opacity))
reg('microchip', 'technical', 'Chip layout pattern', ['chip', 'ic'], (c, w, h) => rect(w*0.2, h*0.2, w*0.6, h*0.6, 'none', c.opacity, 1) + `<rect x="${w*0.2}" y="${h*0.2}" width="${w*0.6}" height="${h*0.6}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}" rx="1"/>` + line(0, h*0.35, w*0.2, h*0.35, c.color, c.strokeWidth*0.5, c.opacity) + line(0, h*0.65, w*0.2, h*0.65, c.color, c.strokeWidth*0.5, c.opacity) + line(w*0.8, h*0.35, w, h*0.35, c.color, c.strokeWidth*0.5, c.opacity) + line(w*0.8, h*0.65, w, h*0.65, c.color, c.strokeWidth*0.5, c.opacity))
reg('binary', 'technical', 'Binary code pattern', ['binary', 'code'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 3; i++) for (let j = 0; j < 4; j++) { const ch = rng() > 0.5 ? '1' : '0'; s += `<text x="${j*w*0.25+w*0.05}" y="${i*h*0.3+h*0.25}" fill="${c.color}" font-size="${Math.min(w,h)*0.2}" font-family="monospace" opacity="${c.opacity*(0.2+rng()*0.4)}">${ch}</text>` } return s })
reg('blueprint-detail', 'technical', 'Detailed blueprint', ['blueprint', 'cad'], (c, w, h) => line(w*0.1, h*0.1, w*0.9, h*0.1, c.color, c.strokeWidth*0.5, c.opacity*0.5) + line(w*0.1, h*0.1, w*0.1, h*0.9, c.color, c.strokeWidth*0.5, c.opacity*0.5) + `<text x="${w*0.15}" y="${h*0.25}" fill="${c.color}" font-size="${Math.min(w,h)*0.12}" font-family="monospace" opacity="${c.opacity*0.3}">A1</text>`)
reg('schematic', 'technical', 'Electronic schematic', ['schematic', 'electronics'], (c, w, h) => path(`M0,${h/2} L${w*0.2},${h/2} L${w*0.3},${h*0.2} L${w*0.4},${h*0.8} L${w*0.5},${h*0.2} L${w*0.6},${h*0.8} L${w*0.7},${h/2} L${w},${h/2}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('resistor', 'technical', 'Resistor zigzag symbol', ['resistor', 'component'], (c, w, h) => path(`M0,${h/2} L${w*0.15},${h/2} L${w*0.22},${h*0.2} L${w*0.36},${h*0.8} L${w*0.5},${h*0.2} L${w*0.64},${h*0.8} L${w*0.78},${h*0.2} L${w*0.85},${h/2} L${w},${h/2}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('waveform', 'technical', 'Oscilloscope waveform', ['waveform', 'signal'], (c, w, h) => { let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) d += ` L${x},${h/2+Math.sin(x/w*Math.PI*4)*h*0.3*c.density}`; return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('barcode', 'technical', 'Barcode lines', ['barcode', 'scan'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; let x = 0; while (x < w) { const bw = 1+Math.floor(rng()*3); s += rect(x, h*0.1, bw, h*0.8, c.color, c.opacity*(0.3+rng()*0.7)); x += bw + 1+Math.floor(rng()*3) } return s })
reg('qr-dots', 'technical', 'QR code style dots', ['qr', 'data'], (c, w, h) => { const rng = seededRng(c.seed); const sz = w/5; let s = ''; for (let r = 0; r < 5; r++) for (let co = 0; co < 5; co++) if (rng() > 0.4) s += rect(co*sz, r*sz, sz-1, sz-1, c.color, c.opacity); return s })
reg('data-matrix', 'technical', 'Data matrix modules', ['data', 'matrix'], (c, w, h) => { const rng = seededRng(c.seed); const sz = w/4; let s = ''; for (let r = 0; r < 4; r++) for (let co = 0; co < 4; co++) if (rng() > 0.5) s += rect(co*sz+0.5, r*sz+0.5, sz-1, sz-1, c.color, c.opacity*(0.4+rng()*0.6)); return s })
reg('graph-line', 'technical', 'Chart line pattern', ['chart', 'data'], (c, w, h) => { const rng = seededRng(c.seed); let d = `M0,${h*(0.3+rng()*0.4)}`; for (let i = 1; i <= 4; i++) d += ` L${i*w/4},${h*(0.2+rng()*0.6)}`; return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('ruler', 'technical', 'Ruler tick marks', ['ruler', 'measurement'], (c, w, h) => { let s = ''; for (let i = 0; i <= 4; i++) { const x = i*w/4, th = i%2===0 ? h*0.5 : h*0.3; s += line(x, 0, x, th, c.color, c.strokeWidth*0.5, c.opacity) } return s })
reg('crosshair', 'technical', 'Crosshair target', ['crosshair', 'target'], (c, w, h) => line(w/2, h*0.1, w/2, h*0.9, c.color, c.strokeWidth*0.5, c.opacity*0.5) + line(w*0.1, h/2, w*0.9, h/2, c.color, c.strokeWidth*0.5, c.opacity*0.5) + `<circle cx="${w/2}" cy="${h/2}" r="${w*0.2}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.5}"/>`)
reg('dimension', 'technical', 'Dimension annotation', ['dimension', 'cad'], (c, w, h) => line(w*0.1, h*0.8, w*0.9, h*0.8, c.color, c.strokeWidth*0.5, c.opacity) + line(w*0.1, h*0.7, w*0.1, h*0.9, c.color, c.strokeWidth*0.5, c.opacity) + line(w*0.9, h*0.7, w*0.9, h*0.9, c.color, c.strokeWidth*0.5, c.opacity))
reg('gear', 'technical', 'Gear tooth pattern', ['gear', 'mechanical'], (c, w, h) => { let d = ''; for (let i = 0; i < 8; i++) { const a1 = i*Math.PI/4, a2 = (i+0.3)*Math.PI/4, r1 = w*0.35, r2 = w*0.28; d += `${i===0?'M':'L'}${w/2+Math.cos(a1)*r1},${h/2+Math.sin(a1)*r1} L${w/2+Math.cos(a2)*r2},${h/2+Math.sin(a2)*r2} ` } return path(d+'Z', 'none', c.color, c.strokeWidth, c.opacity) + `<circle cx="${w/2}" cy="${h/2}" r="${w*0.1}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>` })
reg('pcb-via', 'technical', 'PCB via pads', ['pcb', 'via'], (c, w, h) => `<circle cx="${w/2}" cy="${h/2}" r="${w*0.25}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}"/>` + circle(w/2, h/2, w*0.08, c.color, c.opacity))
reg('flowchart', 'technical', 'Flowchart connector', ['flowchart', 'diagram'], (c, w, h) => rect(w*0.15, h*0.3, w*0.7, h*0.4, 'none', c.opacity) + `<rect x="${w*0.15}" y="${h*0.3}" width="${w*0.7}" height="${h*0.4}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity}" rx="3"/>` + line(w/2, h*0.7, w/2, h, c.color, c.strokeWidth*0.5, c.opacity*0.5))

// ═══ ARTISTIC (16) ═══
reg('watercolor', 'artistic', 'Watercolor wash', ['watercolor', 'paint'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 5; i++) { const cx=rng()*w, cy=rng()*h, rx=3+rng()*w*0.3, ry=2+rng()*h*0.2; s += `<ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${c.color}" opacity="${c.opacity*0.03}"/>` } return s })
reg('ink-splatter', 'artistic', 'Ink splatter spots', ['ink', 'splatter'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*4); i++) { const r = 1+rng()*w*0.12; s += circle(rng()*w, rng()*h, r, c.color, c.opacity*(0.1+rng()*0.3)) } return s })
reg('brush-stroke', 'artistic', 'Brush stroke marks', ['brush', 'paint'], (c, w, h) => path(`M${w*0.05},${h*0.5} Q${w*0.25},${h*0.3} ${w*0.5},${h*0.45} Q${w*0.75},${h*0.6} ${w*0.95},${h*0.4}`, 'none', c.color, c.strokeWidth*2, c.opacity*0.3))
reg('charcoal', 'artistic', 'Charcoal sketch marks', ['charcoal', 'sketch'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*8); i++) { const x1=rng()*w, y1=rng()*h; s += line(x1, y1, x1+rng()*6-3, y1+rng()*6-3, c.color, 0.5+rng()*2, c.opacity*(0.05+rng()*0.15)) } return s })
reg('crayon', 'artistic', 'Crayon scribble', ['crayon', 'childlike'], (c, w, h) => { const rng = seededRng(c.seed); let d = `M${rng()*w},${rng()*h}`; for (let i = 0; i < 5; i++) d += ` Q${rng()*w},${rng()*h} ${rng()*w},${rng()*h}`; return path(d, 'none', c.color, c.strokeWidth*1.5, c.opacity*0.2) })
reg('etching', 'artistic', 'Copper plate etching', ['etching', 'print'], (c, w, h) => { let s = ''; for (let i = 0; i < Math.ceil(c.density*6); i++) s += line(0, i*h/5, w, i*h/5+h*0.05, c.color, c.strokeWidth*0.3, c.opacity*(0.1+i*0.05)); return s })
reg('woodcut', 'artistic', 'Woodcut print lines', ['woodcut', 'print'], (c, w, h) => { let s = ''; for (let i = 0; i < Math.ceil(c.density*8); i++) { const y = i*h/7; s += path(`M0,${y} Q${w*0.3},${y+2} ${w*0.5},${y-1} Q${w*0.7},${y+3} ${w},${y}`, 'none', c.color, c.strokeWidth*0.4, c.opacity*(0.08+i*0.03)) } return s })
reg('linocut', 'artistic', 'Linocut bold strokes', ['linocut', 'print'], (c, w, h) => rect(w*0.1, h*0.15, w*0.35, h*0.7, c.color, c.opacity*0.15, 2) + rect(w*0.55, h*0.25, w*0.35, h*0.5, c.color, c.opacity*0.1, 2))
reg('zentangle', 'artistic', 'Zentangle pattern', ['zentangle', 'meditative'], (c, w, h) => path(`M0,0 Q${w*0.5},${h*0.3} ${w},0 M0,${h*0.33} Q${w*0.5},${h*0.6} ${w},${h*0.33} M0,${h*0.66} Q${w*0.5},${h*0.9} ${w},${h*0.66}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.4))
reg('abstract', 'artistic', 'Abstract composition', ['abstract', 'modern'], (c, w, h) => circle(w*0.3, h*0.3, w*0.15, c.color, c.opacity*0.15) + rect(w*0.5, h*0.4, w*0.35, h*0.3, c.color, c.opacity*0.1, 0) + line(w*0.1, h*0.8, w*0.9, h*0.6, c.color, c.strokeWidth, c.opacity*0.2))
reg('pop-art', 'artistic', 'Pop art benday dots', ['pop', 'benday'], (c, w, h) => circle(w/2, h/2, w*0.4*c.density, c.color, c.opacity*0.4))
reg('art-deco', 'artistic', 'Art deco fan', ['deco', 'gatsby'], (c, w, h) => path(`M0,${h} Q${w*0.5},${h*0.1} ${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity) + path(`M${w*0.2},${h} Q${w*0.5},${h*0.3} ${w*0.8},${h}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.5))
reg('nouveau', 'artistic', 'Art nouveau curve', ['nouveau', 'organic'], (c, w, h) => path(`M0,${h} C${w*0.2},${h*0.2} ${w*0.4},${h*0.8} ${w*0.5},${h*0.3} C${w*0.6},0 ${w*0.8},${h*0.6} ${w},${h*0.1}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('bauhaus', 'artistic', 'Bauhaus geometric', ['bauhaus', 'modernist'], (c, w, h) => circle(w*0.3, h*0.5, w*0.2, c.color, c.opacity*0.15) + rect(w*0.5, h*0.2, w*0.4, h*0.6, 'none', c.opacity) + `<rect x="${w*0.5}" y="${h*0.2}" width="${w*0.4}" height="${h*0.6}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity*0.3}"/>`)
reg('minimalist', 'artistic', 'Minimalist single stroke', ['minimal', 'modern'], (c, w, h) => line(w*0.15, h*0.5, w*0.85, h*0.5, c.color, c.strokeWidth, c.opacity*0.3))
reg('impressionist', 'artistic', 'Impressionist dashes', ['impressionist', 'paint'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*8); i++) { const x=rng()*w, y=rng()*h, a=rng()*180, l=2+rng()*4; s += `<line x1="${x}" y1="${y}" x2="${x+Math.cos(a*Math.PI/180)*l}" y2="${y+Math.sin(a*Math.PI/180)*l}" stroke="${c.color}" stroke-width="${c.strokeWidth}" stroke-linecap="round" opacity="${c.opacity*(0.1+rng()*0.3)}"/>` } return s })

