reg('sine', 'wave', 'Sine wave', ['sine', 'smooth'], (c, w, h) => { let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) d += ` L${x},${h/2+Math.sin(x/w*Math.PI*2)*h*0.3*c.density}`; return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('cosine', 'wave', 'Cosine wave', ['cosine', 'phase'], (c, w, h) => { let d = `M0,${h/2+h*0.3*c.density}`; for (let x = 0; x <= w; x += 2) d += ` L${x},${h/2+Math.cos(x/w*Math.PI*2)*h*0.3*c.density}`; return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('sawtooth', 'wave', 'Sawtooth wave', ['sawtooth', 'angular'], (c, w, h) => path(`M0,${h*0.8} L${w/2},${h*0.2} L${w/2},${h*0.8} L${w},${h*0.2}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('square-wave', 'wave', 'Square wave', ['square', 'digital'], (c, w, h) => path(`M0,${h*0.2} L${w*0.25},${h*0.2} L${w*0.25},${h*0.8} L${w*0.5},${h*0.8} L${w*0.5},${h*0.2} L${w*0.75},${h*0.2} L${w*0.75},${h*0.8} L${w},${h*0.8}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('triangle-wave', 'wave', 'Triangle wave', ['triangle', 'linear'], (c, w, h) => path(`M0,${h/2} L${w*0.25},${h*0.15} L${w*0.5},${h/2} L${w*0.75},${h*0.85} L${w},${h/2}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('ocean', 'wave', 'Ocean wave', ['ocean', 'water'], (c, w, h) => path(`M0,${h*0.6} Q${w*0.15},${h*0.3} ${w*0.3},${h*0.5} Q${w*0.45},${h*0.7} ${w*0.6},${h*0.4} Q${w*0.8},${h*0.2} ${w},${h*0.5}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('ripple', 'wave', 'Ripple from center', ['ripple', 'water'], (c, w, h) => { let s = ''; for (let i = 1; i <= 3; i++) s += `<circle cx="${w/2}" cy="${h/2}" r="${i*w*0.12*c.density}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*(1-i*0.25)}"/>`; return s })
reg('seismic', 'wave', 'Seismic waveform', ['seismic', 'earthquake'], (c, w, h) => { const rng = seededRng(c.seed); let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) { const amp = rng() > 0.7 ? h*0.35 : h*0.05; d += ` L${x},${h/2+(rng()-0.5)*2*amp*c.density}` } return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('pulse', 'wave', 'Pulse blip', ['pulse', 'heartbeat'], (c, w, h) => path(`M0,${h/2} L${w*0.3},${h/2} L${w*0.35},${h*0.1} L${w*0.4},${h*0.85} L${w*0.45},${h*0.3} L${w*0.5},${h/2} L${w},${h/2}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('interference', 'wave', 'Wave interference', ['interference', 'physics'], (c, w, h) => { let d1 = `M0,${h/2}`, d2 = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) { d1 += ` L${x},${h/2+Math.sin(x/w*Math.PI*3)*h*0.2*c.density}`; d2 += ` L${x},${h/2+Math.sin(x/w*Math.PI*4+1)*h*0.15*c.density}` } return path(d1, 'none', c.color, c.strokeWidth, c.opacity*0.5) + path(d2, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.3) })
reg('standing-wave', 'wave', 'Standing wave nodes', ['standing', 'resonance'], (c, w, h) => { let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) { const env = Math.sin(x/w*Math.PI); d += ` L${x},${h/2+Math.sin(x/w*Math.PI*6)*h*0.3*env*c.density}` } return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('sound-wave', 'wave', 'Audio waveform', ['sound', 'audio'], (c, w, h) => { let s = ''; for (let x = 0; x < w; x += 3) { const amp = Math.abs(Math.sin(x/w*Math.PI*5))*h*0.35*c.density; s += line(x, h/2-amp, x, h/2+amp, c.color, 1, c.opacity) } return s })
reg('frequency', 'wave', 'Frequency spectrum', ['frequency', 'spectrum'], (c, w, h) => { let s = ''; const bars = 12; for (let i = 0; i < bars; i++) { const amp = Math.abs(Math.sin(i*0.8))*h*0.6*c.density; s += rect(i*w/bars+1, h/2-amp/2, w/bars-2, amp, c.color, c.opacity*(0.3+amp/(h*0.6)*0.7)) } return s })
reg('modulated', 'wave', 'AM modulated wave', ['modulated', 'radio'], (c, w, h) => { let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 1) { const env = 0.3+Math.sin(x/w*Math.PI*2)*0.7; d += ` L${x},${h/2+Math.sin(x/w*Math.PI*12)*h*0.25*env*c.density}` } return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('noise-wave', 'wave', 'Noisy wave signal', ['noise', 'static'], (c, w, h) => { const rng = seededRng(c.seed); let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) d += ` L${x},${h/2+(Math.sin(x/w*Math.PI*3)+rng()*0.5-0.25)*h*0.25*c.density}`; return path(d, 'none', c.color, c.strokeWidth, c.opacity) })
reg('damped', 'wave', 'Damped oscillation', ['damped', 'spring'], (c, w, h) => { let d = `M0,${h/2}`; for (let x = 0; x <= w; x += 2) { const decay = Math.exp(-x/w*3); d += ` L${x},${h/2+Math.sin(x/w*Math.PI*6)*h*0.35*decay*c.density}` } return path(d, 'none', c.color, c.strokeWidth, c.opacity) })

// ═══ NOISE (16) ═══
reg('perlin', 'noise', 'Perlin-like noise', ['perlin', 'smooth'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*20); i++) { const x=rng()*w, y=rng()*h, r=0.3+rng()*1.5; s += circle(x, y, r, c.color, c.opacity*(0.02+rng()*0.08)) } return s })
reg('simplex', 'noise', 'Simplex-like noise', ['simplex', 'terrain'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*15); i++) { const x=rng()*w, y=rng()*h; s += `<ellipse cx="${x}" cy="${y}" rx="${1+rng()*3}" ry="${0.5+rng()*2}" fill="${c.color}" opacity="${c.opacity*(0.02+rng()*0.06)}" transform="rotate(${rng()*180},${x},${y})"/>` } return s })
reg('white-noise', 'noise', 'White noise static', ['white', 'random'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*30); i++) s += rect(Math.floor(rng()*w), Math.floor(rng()*h), 1, 1, c.color, c.opacity*(rng()*0.15)); return s })
reg('pink-noise', 'noise', 'Pink noise (1/f)', ['pink', 'smooth'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*12); i++) { const sz = 0.5+rng()*3; s += rect(rng()*w, rng()*h, sz, sz, c.color, c.opacity*(0.03+rng()*0.07)) } return s })
reg('brown-noise', 'noise', 'Brownian motion noise', ['brown', 'drift'], (c, w, h) => { const rng = seededRng(c.seed); let d = `M${rng()*w},${rng()*h}`, x = rng()*w, y = rng()*h; for (let i = 0; i < 10; i++) { x += (rng()-0.5)*w*0.3; y += (rng()-0.5)*h*0.3; d += ` L${x},${y}` } return path(d, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.15) })
reg('voronoi', 'noise', 'Voronoi cell edges', ['voronoi', 'cell'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < 4; i++) { const cx=w*0.2+rng()*w*0.6, cy=h*0.2+rng()*h*0.6; s += circle(cx, cy, 1, c.color, c.opacity*0.5) } return s + line(w*0.5, 0, w*0.4, h, c.color, c.strokeWidth*0.3, c.opacity*0.15) })
reg('worley', 'noise', 'Worley noise points', ['worley', 'cellular'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*6); i++) s += circle(rng()*w, rng()*h, 0.8+rng()*1.5, c.color, c.opacity*(0.1+rng()*0.3)); return s })
reg('fractal', 'noise', 'Fractal noise layers', ['fractal', 'fbm'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let oct = 0; oct < 3; oct++) { const count = Math.ceil(c.density*(5+oct*5)); for (let i = 0; i < count; i++) { const sz = Math.max(0.3, 3/(oct+1)); s += circle(rng()*w, rng()*h, sz*rng(), c.color, c.opacity*(0.02+rng()*0.04)) } } return s })
reg('turbulence', 'noise', 'SVG turbulence approximation', ['turbulence', 'distort'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*18); i++) { const x=rng()*w, y=rng()*h, a=rng()*360; s += `<ellipse cx="${x}" cy="${y}" rx="${0.5+rng()*2}" ry="${0.3+rng()*1}" fill="${c.color}" opacity="${c.opacity*(0.02+rng()*0.05)}" transform="rotate(${a},${x},${y})"/>` } return s })
reg('cloud-noise', 'noise', 'Cloud formation noise', ['cloud', 'atmospheric'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*8); i++) { const cx=rng()*w, cy=rng()*h, rx=3+rng()*w*0.15, ry=2+rng()*h*0.1; s += `<ellipse cx="${cx}" cy="${cy}" rx="${rx}" ry="${ry}" fill="${c.color}" opacity="${c.opacity*0.03}"/>` } return s })
reg('galaxy', 'noise', 'Galaxy spiral noise', ['galaxy', 'space'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*20); i++) { const a = rng()*Math.PI*4, r = rng()*w*0.4, x = w/2+Math.cos(a)*r, y = h/2+Math.sin(a)*r; s += circle(x, y, 0.3+rng()*0.7, c.color, c.opacity*(0.05+rng()*0.15)) } return s })
reg('plasma', 'noise', 'Plasma field', ['plasma', 'energy'], (c, w, h) => { let s = ''; for (let i = 0; i < 5; i++) { const cx = w*(0.2+i*0.15), cy = h*(0.3+Math.sin(i)*0.2), r = w*0.15+i*2; s += `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${c.color}" opacity="${c.opacity*0.02}"/>` } return s })
reg('static', 'noise', 'TV static', ['static', 'tv'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; const sz = 2; for (let r = 0; r < Math.ceil(h/sz); r++) for (let co = 0; co < Math.ceil(w/sz); co++) if (rng() > 0.5) s += rect(co*sz, r*sz, sz, sz, c.color, c.opacity*(rng()*0.1)); return s })
reg('dither', 'noise', 'Ordered dither pattern', ['dither', 'bayer'], (c, w, h) => { const m = [[0,8,2,10],[12,4,14,6],[3,11,1,9],[15,7,13,5]]; let s = ''; const sz = w/4; for (let r = 0; r < 4; r++) for (let co = 0; co < 4; co++) if (m[r][co]/16 < c.density) s += rect(co*sz, r*sz, sz, sz, c.color, c.opacity*0.15); return s })
reg('grain', 'noise', 'Photo grain overlay', ['grain', 'photo'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*35); i++) s += rect(rng()*w, rng()*h, rng()>.5?1:0.5, rng()>.5?1:0.5, c.color, c.opacity*(0.01+rng()*0.04)); return s })
reg('speckle', 'noise', 'Speckle noise', ['speckle', 'dirty'], (c, w, h) => { const rng = seededRng(c.seed); let s = ''; for (let i = 0; i < Math.ceil(c.density*12); i++) s += circle(rng()*w, rng()*h, 0.3+rng()*1.2, c.color, c.opacity*(0.05+rng()*0.1)); return s })

// ═══ CULTURAL (12) ═══
reg('sashiko', 'cultural', 'Japanese sashiko stitch', ['sashiko', 'japanese'], (c, w, h) => `<line x1="0" y1="${h/2}" x2="${w}" y2="${h/2}" stroke="${c.color}" stroke-width="${c.strokeWidth}" stroke-dasharray="${w*0.15} ${w*0.08}" opacity="${c.opacity}"/>`)
reg('seigaiha', 'cultural', 'Japanese wave (seigaiha)', ['seigaiha', 'japanese'], (c, w, h) => path(`M0,${h} Q${w/2},${h*0.1} ${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity) + path(`M${-w*0.15},${h} Q${w*0.35},${h*0.25} ${w*0.85},${h}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.4))
reg('asanoha', 'cultural', 'Hemp leaf (asanoha)', ['asanoha', 'japanese'], (c, w, h) => line(w/2, 0, w/2, h, c.color, c.strokeWidth*0.5, c.opacity) + line(0, h/2, w, h/2, c.color, c.strokeWidth*0.5, c.opacity) + line(0, 0, w, h, c.color, c.strokeWidth*0.5, c.opacity*0.5) + line(w, 0, 0, h, c.color, c.strokeWidth*0.5, c.opacity*0.5))
reg('moroccan', 'cultural', 'Moroccan zellige tile', ['moroccan', 'zellige'], (c, w, h) => { const cx=w/2, cy=h/2, r=w*0.4; let d = ''; for (let i = 0; i < 8; i++) { const a = i*Math.PI/4; d += `M${cx},${cy} L${cx+Math.cos(a)*r},${cy+Math.sin(a)*r} ` } return path(d, 'none', c.color, c.strokeWidth*0.5, c.opacity) })
reg('celtic-knot', 'cultural', 'Celtic interlace', ['celtic', 'knot'], (c, w, h) => path(`M${w*0.1},${h/2} C${w*0.3},${h*0.1} ${w*0.7},${h*0.9} ${w*0.9},${h/2}`, 'none', c.color, c.strokeWidth, c.opacity) + path(`M${w/2},${h*0.1} C${w*0.1},${h*0.3} ${w*0.9},${h*0.7} ${w/2},${h*0.9}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('greek-key', 'cultural', 'Greek meander key', ['greek', 'meander'], (c, w, h) => path(`M0,${h*0.8} L0,${h*0.2} L${w*0.6},${h*0.2} L${w*0.6},${h*0.6} L${w*0.2},${h*0.6} L${w*0.2},${h*0.8} L${w},${h*0.8}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('aztec', 'cultural', 'Aztec stepped pattern', ['aztec', 'mesoamerican'], (c, w, h) => path(`M0,${h} L0,${h*0.6} L${w*0.25},${h*0.6} L${w*0.25},${h*0.3} L${w*0.5},${h*0.3} L${w*0.5},0 L${w*0.75},0 L${w*0.75},${h*0.3} L${w},${h*0.3} L${w},${h}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('tribal', 'cultural', 'Tribal line pattern', ['tribal', 'ethnic'], (c, w, h) => line(0, h*0.3, w, h*0.3, c.color, c.strokeWidth, c.opacity) + line(0, h*0.7, w, h*0.7, c.color, c.strokeWidth, c.opacity) + path(`M${w*0.2},${h*0.3} L${w*0.5},${h*0.7} L${w*0.8},${h*0.3}`, 'none', c.color, c.strokeWidth*0.5, c.opacity*0.6))
reg('ikat', 'cultural', 'Ikat weave blur', ['ikat', 'textile'], (c, w, h) => path(`M${w*0.3},0 L${w*0.5},${h*0.5} L${w*0.3},${h}`, 'none', c.color, c.strokeWidth*2, c.opacity*0.2) + path(`M${w*0.7},0 L${w*0.5},${h*0.5} L${w*0.7},${h}`, 'none', c.color, c.strokeWidth*2, c.opacity*0.2))
reg('kente', 'cultural', 'Kente cloth weave', ['kente', 'african'], (c, w, h) => rect(0, h*0.2, w, h*0.15, c.color, c.opacity*0.15) + rect(0, h*0.65, w, h*0.15, c.color, c.opacity*0.1) + rect(w*0.2, 0, w*0.15, h, c.color, c.opacity*0.12) + rect(w*0.65, 0, w*0.15, h, c.color, c.opacity*0.08))
reg('paisley', 'cultural', 'Paisley teardrop', ['paisley', 'persian'], (c, w, h) => path(`M${w*0.5},${h*0.1} Q${w*0.8},${h*0.3} ${w*0.6},${h*0.7} Q${w*0.5},${h*0.9} ${w*0.4},${h*0.7} Q${w*0.2},${h*0.3} ${w*0.5},${h*0.1}`, 'none', c.color, c.strokeWidth, c.opacity))
reg('mandala', 'cultural', 'Mandala radial', ['mandala', 'spiritual'], (c, w, h) => { let s = `<circle cx="${w/2}" cy="${h/2}" r="${w*0.35}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.5}"/>`; for (let i = 0; i < 8; i++) { const a = i*Math.PI/4, r = w*0.35; s += line(w/2, h/2, w/2+Math.cos(a)*r, h/2+Math.sin(a)*r, c.color, c.strokeWidth*0.3, c.opacity*0.3) } return s })

// ═══ TYPOGRAPHY (8) ═══
reg('hash', 'typography', 'Hash # symbols', ['hash', 'code'], (c, w, h) => `<text x="${w*0.2}" y="${h*0.65}" fill="${c.color}" font-size="${Math.min(w,h)*0.5}" font-family="monospace" opacity="${c.opacity*0.2}">#</text>`)
reg('asterisk', 'typography', 'Asterisk stars', ['asterisk', 'star'], (c, w, h) => `<text x="${w*0.25}" y="${h*0.7}" fill="${c.color}" font-size="${Math.min(w,h)*0.6}" font-family="monospace" opacity="${c.opacity*0.2}">*</text>`)
reg('dots-ellipsis', 'typography', 'Ellipsis dots', ['ellipsis', 'dots'], (c, w, h) => `<text x="${w*0.1}" y="${h*0.6}" fill="${c.color}" font-size="${Math.min(w,h)*0.4}" font-family="monospace" opacity="${c.opacity*0.2}">...</text>`)
reg('brackets', 'typography', 'Curly brackets', ['bracket', 'code'], (c, w, h) => `<text x="${w*0.15}" y="${h*0.65}" fill="${c.color}" font-size="${Math.min(w,h)*0.5}" font-family="monospace" opacity="${c.opacity*0.2}">{ }</text>`)
reg('slashes', 'typography', 'Forward slashes', ['slash', 'code'], (c, w, h) => `<text x="${w*0.2}" y="${h*0.7}" fill="${c.color}" font-size="${Math.min(w,h)*0.5}" font-family="monospace" opacity="${c.opacity*0.15}">///</text>`)
reg('at-sign', 'typography', '@ symbols', ['at', 'email'], (c, w, h) => `<text x="${w*0.15}" y="${h*0.7}" fill="${c.color}" font-size="${Math.min(w,h)*0.55}" font-family="monospace" opacity="${c.opacity*0.15}">@</text>`)
reg('ampersand', 'typography', 'Ampersand symbols', ['ampersand', 'and'], (c, w, h) => `<text x="${w*0.15}" y="${h*0.72}" fill="${c.color}" font-size="${Math.min(w,h)*0.6}" font-family="serif" opacity="${c.opacity*0.12}">&amp;</text>`)
reg('tilde', 'typography', 'Tilde waves', ['tilde', 'approx'], (c, w, h) => `<text x="${w*0.15}" y="${h*0.6}" fill="${c.color}" font-size="${Math.min(w,h)*0.5}" font-family="monospace" opacity="${c.opacity*0.15}">~~~</text>`)


reg('plus-sign', 'typography', 'Plus sign grid', ['plus', 'math'], (c, w, h) => `<text x="${w*0.2}" y="${h*0.68}" fill="${c.color}" font-size="${Math.min(w,h)*0.55}" font-family="monospace" opacity="${c.opacity*0.15}">+</text>`)
reg('pipe', 'typography', 'Pipe separator', ['pipe', 'divider'], (c, w, h) => `<text x="${w*0.3}" y="${h*0.7}" fill="${c.color}" font-size="${Math.min(w,h)*0.55}" font-family="monospace" opacity="${c.opacity*0.12}">|</text>`)

