export function getRenderer(name: string): RenderFn | null { return P[name] || null }
export function getMeta(name: string): PatternMeta | null { return META[name] || null }
export function getAllPatternNames(): string[] { return Object.keys(P) }
export function getPatternsByCategory(cat: PatternCategory): string[] { return Object.keys(META).filter(n => META[n].category === cat) }
export function getAllMeta(): Record<string, PatternMeta> { return { ...META } }
export { P as renderers }
